import Foundation
import WebKit

/// Serves the markdown panel's in-panel Monaco editor over a per-panel custom
/// scheme: the generated editor page at `/index.html` plus the bundled
/// webviews assets (`main.mjs`, chunks, Monaco worker + stylesheet) read
/// straight from the app bundle.
///
/// This is the in-process counterpart of the diff-viewer serving that backs
/// `cmux edit`: because the page and its config are generated by the app from
/// panel-owned state, nothing is staged on disk and no cross-process token
/// capability is needed. The random token host still scopes the origin per
/// panel so the save message handler can verify the frame it talks to.
///
/// Large vendor chunks ship raw-DEFLATE compressed in the bundle
/// (`*.mjs.deflate`, see `scripts/build-webviews-app.sh`); they are inflated
/// on first request and cached for the app's lifetime.
///
/// WebKit invokes scheme-handler callbacks on the main thread (the webviews
/// are main-thread objects); only asset reads hop to a background queue and
/// rejoin the main thread before touching the task.
final class MarkdownEditorSchemeHandler: NSObject, WKURLSchemeHandler {
    static let scheme = "cmux-markdown-editor"

    let token: String
    private var pageHTML = Data()
    private var activeTaskIDs: Set<ObjectIdentifier> = []

    /// Inflated `.deflate` assets keyed by bundle-relative path. Static so
    /// every open markdown editor shares one inflation of `monaco-vendor`.
    private static let inflatedAssetCache: NSCache<NSString, NSData> = {
        let cache = NSCache<NSString, NSData>()
        cache.totalCostLimit = 32 * 1024 * 1024
        return cache
    }()

    private static let assetRootURL: URL? = Bundle.main.resourceURL?
        .appendingPathComponent("markdown-viewer", isDirectory: true)
        .appendingPathComponent("webviews-app", isDirectory: true)
        .standardizedFileURL
        .resolvingSymlinksInPath()

    init(token: String) {
        self.token = token
    }

    var pageURL: URL? {
        URL(string: "\(Self.scheme)://\(token)/index.html")
    }

    /// Replaces the served page. Main-thread only, like every other entry
    /// point on this handler (WebKit delivers scheme callbacks on main).
    func updatePage(html: String) {
        pageHTML = Data(html.utf8)
    }

    func webView(_ webView: WKWebView, start urlSchemeTask: WKURLSchemeTask) {
        let taskID = ObjectIdentifier(urlSchemeTask as AnyObject)
        guard let requestURL = urlSchemeTask.request.url,
              requestURL.scheme == Self.scheme,
              requestURL.host == token,
              requestURL.query == nil,
              let requestPath = Self.requestPathComponents(for: requestURL) else {
            urlSchemeTask.didFailWithError(NSError(domain: NSURLErrorDomain, code: NSURLErrorFileDoesNotExist))
            return
        }

        activeTaskIDs.insert(taskID)
        if requestPath == ["index.html"] {
            deliver(pageHTML, mimeType: "text/html", requestURL: requestURL, taskID: taskID, urlSchemeTask: urlSchemeTask)
            return
        }

        guard let mimeType = Self.assetMimeType(for: requestPath),
              let fileURL = Self.assetFileURL(for: requestPath) else {
            activeTaskIDs.remove(taskID)
            urlSchemeTask.didFailWithError(NSError(domain: NSURLErrorDomain, code: NSURLErrorFileDoesNotExist))
            return
        }

        let relativePath = requestPath.joined(separator: "/")
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            let data = Self.loadAssetData(fileURL: fileURL, cacheKey: relativePath)
            DispatchQueue.main.async {
                guard let self, self.activeTaskIDs.contains(taskID) else { return }
                guard let data else {
                    self.activeTaskIDs.remove(taskID)
                    urlSchemeTask.didFailWithError(NSError(domain: NSURLErrorDomain, code: NSURLErrorFileDoesNotExist))
                    return
                }
                self.deliver(data, mimeType: mimeType, requestURL: requestURL, taskID: taskID, urlSchemeTask: urlSchemeTask)
            }
        }
    }

    func webView(_ webView: WKWebView, stop urlSchemeTask: WKURLSchemeTask) {
        activeTaskIDs.remove(ObjectIdentifier(urlSchemeTask as AnyObject))
    }

    private func deliver(
        _ data: Data,
        mimeType: String,
        requestURL: URL,
        taskID: ObjectIdentifier,
        urlSchemeTask: WKURLSchemeTask
    ) {
        guard activeTaskIDs.contains(taskID) else { return }
        defer { activeTaskIDs.remove(taskID) }
        let response = HTTPURLResponse(
            url: requestURL,
            statusCode: 200,
            httpVersion: "HTTP/1.1",
            headerFields: Self.responseHeaders(mimeType: mimeType)
        ) ?? URLResponse(
            url: requestURL,
            mimeType: mimeType,
            expectedContentLength: data.count,
            textEncodingName: "utf-8"
        )
        urlSchemeTask.didReceive(response)
        if !data.isEmpty {
            urlSchemeTask.didReceive(data)
        }
        urlSchemeTask.didFinish()
    }

    /// Same headers the diff-viewer scheme handler sends, including the page
    /// CSP the editor surface is written against (inline injected styles,
    /// same-origin scripts + worker, `fetch` of the Monaco stylesheet).
    static func responseHeaders(mimeType: String) -> [String: String] {
        var headers = [
            "Content-Type": "\(mimeType); charset=utf-8",
            "Cache-Control": "no-store",
            "X-Content-Type-Options": "nosniff",
            "Cross-Origin-Resource-Policy": "same-origin"
        ]
        if mimeType == "text/html" {
            headers["Content-Security-Policy"] = [
                "default-src 'none'",
                "script-src 'self' 'unsafe-inline' 'wasm-unsafe-eval'",
                "style-src 'unsafe-inline'",
                "img-src 'self' data:",
                "connect-src 'self'",
                "font-src 'none'",
                "object-src 'none'",
                "base-uri 'none'",
                "form-action 'none'"
            ].joined(separator: "; ")
        }
        return headers
    }

    /// Splits and validates the request path: no empty, `.`, or `..`
    /// components, so a request can never escape the bundle asset root.
    static func requestPathComponents(for url: URL) -> [String]? {
        let components = url.path.split(separator: "/", omittingEmptySubsequences: false).dropFirst().map(String.init)
        guard !components.isEmpty,
              components.allSatisfy({ !$0.isEmpty && $0 != "." && $0 != ".." && !$0.contains("\\") }) else {
            return nil
        }
        return components
    }

    /// Only the bundled webviews module/stylesheet types are servable; the
    /// generated page is the single HTML entry.
    static func assetMimeType(for pathComponents: [String]) -> String? {
        guard let fileName = pathComponents.last else { return nil }
        if fileName.hasSuffix(".mjs") || fileName.hasSuffix(".js") {
            return "text/javascript"
        }
        if fileName.hasSuffix(".css") {
            return "text/css"
        }
        return nil
    }

    static func assetFileURL(for pathComponents: [String]) -> URL? {
        guard let root = assetRootURL else { return nil }
        var fileURL = root
        for component in pathComponents {
            fileURL.appendPathComponent(component, isDirectory: false)
        }
        let standardized = fileURL.standardizedFileURL
        guard standardized.path.hasPrefix(root.path + "/") else { return nil }
        return standardized
    }

    /// Reads a bundle asset, inflating the `.deflate` sibling when the raw
    /// file is not shipped. Returns `nil` when neither exists.
    private static func loadAssetData(fileURL: URL, cacheKey: String) -> Data? {
        if let cached = inflatedAssetCache.object(forKey: cacheKey as NSString) {
            return cached as Data
        }
        if let raw = try? Data(contentsOf: fileURL) {
            return raw
        }
        let deflateURL = fileURL.appendingPathExtension("deflate")
        guard let compressed = try? Data(contentsOf: deflateURL),
              // `.deflate` files are RAW deflate streams (node
              // `zlib.deflateRawSync`); Apple's `.zlib` algorithm decodes raw
              // deflate, matching the CLI's inflation on copy.
              let inflated = try? (compressed as NSData).decompressed(using: .zlib) as Data else {
            return nil
        }
        inflatedAssetCache.setObject(inflated as NSData, forKey: cacheKey as NSString, cost: inflated.count)
        return inflated
    }
}
